        virtual ~MDLoadingPresenter(){}
        virtual std::string getWorkspaceTypeName()
        {
          return "NotSet";
        }
        virtual int getSpecialCoordinates()
        {
        return Kernel::None;
        }

        /**
         * Gets the minimum value.
         * @returns The minimum value of the dataset or 0.0
         */
        virtual double getMinValue()
        {
          return 0.0;
        };

